"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[49478],{51085:e=>{e.exports=JSON.parse('{"tag":{"label":"health","permalink":"/docs/tags/health","allTagsPath":"/docs/tags","count":53,"items":[{"id":"Rats/getting-started/rat-care-guide","title":"A Comprehensive Guide to Rat Care","description":"Rats are intelligent, social, and engaging pets that bring a unique joy to any home. To ensure they live long, happy, and healthy lives, it\u2019s essential to understand and meet their specific needs. This guide provides a comprehensive overview of daily and weekly care routines for your pet rats.","permalink":"/docs/Rats/getting-started/rat-care-guide"},{"id":"Rats/breeds-and-genetics/rat-variety-guide","title":"A Guide to Fancy Rat Varieties","description":"Welcome to the colorful world of fancy rats! Through selective breeding, pet rats have been developed in a stunning array of colors, coat types, and markings. While these varieties are fascinating,...","permalink":"/docs/Rats/breeds-and-genetics/rat-variety-guide"},{"id":"Rats/getting-started/rat-nutrition-guide","title":"A Guide to Proper Rat Nutrition","description":"Proper nutrition is the cornerstone of your pet rat\'s health and longevity. As omnivores, rats have specific dietary needs that must be met to prevent obesity, nutritional deficiencies, and other...","permalink":"/docs/Rats/getting-started/rat-nutrition-guide"},{"id":"Rats/health-and-wellness/rat-introductions","title":"A Guide to Safe and Successful Rat Introductions","description":"Introducing a new rat to your existing group (or \'mischief\') is an exciting step, but it must be handled with care and patience. Rats are territorial and have complex social hierarchies. A proper...","permalink":"/docs/Rats/health-and-wellness/rat-introductions"},{"id":"guinea-pigs/illnesses-and-conditions/bumblefoot-in-guinea-pigs","title":"Bumblefoot in Guinea Pigs","description":"Learn about bumblefoot (pododermatitis) in guinea pigs \u2014 causes, warning signs, treatment, and how to prevent this painful foot condition with proper housing.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/bumblefoot-in-guinea-pigs"},{"id":"guinea-pigs/illnesses-and-conditions/coccidia-in-guinea-pigs","title":"Coccidia in Guinea Pigs","description":"Understand coccidia in guinea pigs \u2014 what it is, how it spreads, symptoms to watch for, how it\'s diagnosed and treated, and how to prevent it.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/coccidia-in-guinea-pigs"},{"id":"Rats/getting-started/the-ideal-rat-habitat-guide","title":"Creating the Ideal Habitat for Your Pet Rats","description":"A well-designed habitat is crucial for the health, happiness, and safety of your pet rats. As active, intelligent, and social creatures, they need a space that supports their natural behaviors like...","permalink":"/docs/Rats/getting-started/the-ideal-rat-habitat-guide"},{"id":"Chinchillas/illnesses-and-conditions/dental-disease-in-chinchillas","title":"Dental Disease in Chinchillas","description":"Learn about the causes, symptoms, and treatment of dental disease and malocclusion in chinchillas, including how diet and genetics play a role.","permalink":"/docs/Chinchillas/illnesses-and-conditions/dental-disease-in-chinchillas"},{"id":"guinea-pigs/health-and-wellness/dental-disease","title":"Dental Disease in Guinea Pigs","description":"Dental disease is one of the most common and serious health problems affecting guinea pigs. Unlike humans, a guinea pig\'s teeth grow continuously throughout their life. This continuous growth can...","permalink":"/docs/guinea-pigs/health-and-wellness/dental-disease"},{"id":"Chinchillas/illnesses-and-conditions/diabetes-in-chinchillas","title":"Diabetes in Chinchillas","description":"Learn about the causes, symptoms, diagnosis, and management of diabetes mellitus in chinchillas, including diet and lifestyle changes.","permalink":"/docs/Chinchillas/illnesses-and-conditions/diabetes-in-chinchillas"},{"id":"Degus/illnesses-and-conditions/diabetes-in-degus","title":"Diabetes in Degus","description":"Learn about the causes, symptoms, diagnosis, and management of diabetes mellitus in degus \u2014 one of the most diabetes-prone small mammals kept as pets.","permalink":"/docs/Degus/illnesses-and-conditions/diabetes-in-degus"},{"id":"guinea-pigs/illnesses-and-conditions/diabetes-in-guinea-pigs","title":"Diabetes in Guinea Pigs","description":"Learn about diabetes mellitus in guinea pigs \u2014 causes, symptoms, diagnosis, management, and how diet and lifestyle changes can help your guinea pig live well.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/diabetes-in-guinea-pigs"},{"id":"Hedgehogs/illnesses-and-conditions/diabetes-in-hedgehogs","title":"Diabetes in Hedgehogs","description":"A comprehensive guide to diabetes in hedgehogs \u2014 causes, signs, diagnosis, and management strategies for this common metabolic condition.","permalink":"/docs/Hedgehogs/illnesses-and-conditions/diabetes-in-hedgehogs"},{"id":"Hamsters/illnesses-and-conditions/diabetes-in-hamsters","title":"Diabetes in Pet Hamsters","description":"A comprehensive guide to diabetes in hamsters \u2014 which breeds are most at risk, signs and symptoms, diagnosis, and management strategies.","permalink":"/docs/Hamsters/illnesses-and-conditions/diabetes-in-hamsters"},{"id":"Mice/illnesses-and-conditions/diabetes-in-mice","title":"Diabetes in Pet Mice","description":"A guide to diabetes in pet mice \u2014 causes, symptoms, diagnosis, and management strategies for this metabolic condition.","permalink":"/docs/Mice/illnesses-and-conditions/diabetes-in-mice"},{"id":"Rabbits/illnesses-and-conditions/diabetes-in-rabbits","title":"Diabetes in Pet Rabbits","description":"A comprehensive guide to diabetes in rabbits \u2014 causes, symptoms, diagnosis, and management of this rare but serious metabolic condition.","permalink":"/docs/Rabbits/illnesses-and-conditions/diabetes-in-rabbits"},{"id":"Rats/illnesses-and-conditions/diabetes-in-rats","title":"Diabetes in Rats","description":"Diabetes Mellitus is a condition in which the body either fails to produce enough insulin or cannot use it effectively, resulting in persistently high blood sugar (hyperglycemia). While not common in pet rats, it does occur \u2014 particularly in older or overweight individuals \u2014 and requires prompt veterinary attention and a committed management plan. Understanding the signs, how diagnosis works, and what treatment looks like can make a significant difference for an affected rat 1.","permalink":"/docs/Rats/illnesses-and-conditions/diabetes-in-rats"},{"id":"guinea-pigs/illnesses-and-conditions/e-cuniculi-in-guinea-pigs","title":"E. cuniculi in Guinea Pigs","description":"Learn about Encephalitozoon cuniculi (E. cuniculi) in guinea pigs \u2014 what it is, how it spreads, symptoms including head tilt and seizures, diagnosis, treatment, and prevention.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/e-cuniculi-in-guinea-pigs"},{"id":"guinea-pigs/illnesses-and-conditions/ear-infections-in-guinea-pigs","title":"Ear Infections in Guinea Pigs","description":"Learn about ear infections in guinea pigs \u2014 causes, warning signs including head tilt and loss of balance, diagnosis, treatment, and how to prevent them.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/ear-infections-in-guinea-pigs"},{"id":"Rabbits/illnesses-and-conditions/ear-infections-in-rabbits","title":"Ear Infections in Rabbits","description":"A guide to ear infections in rabbits \u2014 types, causes, symptoms, diagnosis, treatment, and prevention of otitis in pet rabbits.","permalink":"/docs/Rabbits/illnesses-and-conditions/ear-infections-in-rabbits"},{"id":"Rabbits/getting-started/essential-supplies-for-rabbits","title":"Essential Supplies for Your Rabbit Companion","description":"Bringing a rabbit into your home is a long-term commitment, and providing the right supplies is the first step to ensuring a happy, healthy life for your new friend. Rabbits have specific needs that...","permalink":"/docs/Rabbits/getting-started/essential-supplies-for-rabbits"},{"id":"guinea-pigs/health-and-wellness/eye-health","title":"Eye Health and Vision Issues in Guinea Pigs","description":"Guinea pig eyes are large, bright, and positioned on the sides of their head, giving them a wide field of vision to watch for predators. While generally robust, their eyes are susceptible to a range...","permalink":"/docs/guinea-pigs/health-and-wellness/eye-health"},{"id":"guinea-pigs/illnesses-and-conditions/fleas","title":"Fleas in Guinea Pigs: Causes, Symptoms, Treatment, and Prevention","description":"Fleas are common parasites that can affect various pets, including guinea pigs. While these small, wingless insects are more frequently associated with cats and dogs, a flea infestation can cause...","permalink":"/docs/guinea-pigs/illnesses-and-conditions/fleas"},{"id":"Rabbits/illnesses-and-conditions/fly-strike-in-rabbits","title":"Fly Strike (Myiasis) in Rabbits: A Veterinary Emergency","description":"Fly strike, also known as myiasis, is a devastating and rapidly progressing condition that is a true veterinary emergency. It occurs when flies, typically blowflies, lay eggs on a rabbit. These eggs...","permalink":"/docs/Rabbits/illnesses-and-conditions/fly-strike-in-rabbits"},{"id":"guinea-pigs/illnesses-and-conditions/giardia-in-guinea-pigs","title":"Giardia in Guinea Pigs","description":"Learn about Giardia in guinea pigs \u2014 what it is, how it spreads, symptoms, diagnosis, treatment, and how to prevent this intestinal parasite.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/giardia-in-guinea-pigs"},{"id":"guinea-pigs/health-and-wellness/guineapigpoop","title":"Guinea Pig Poop","description":"Guinea pigs have sensitive digestive systems, and looking at their poop is the best way to quickly determine how your guinea pig\'s system is functioning. It\'s also one of the reasons why it\'s so...","permalink":"/docs/guinea-pigs/health-and-wellness/guineapigpoop"},{"id":"Chinchillas/illnesses-and-conditions/heat-stroke-in-chinchillas","title":"Heat Stroke in Chinchillas","description":"Learn how to recognize, prevent, and respond to heat stroke in chinchillas, including emergency first aid and safe temperature ranges.","permalink":"/docs/Chinchillas/illnesses-and-conditions/heat-stroke-in-chinchillas"},{"id":"Degus/health-and-wellness/home-health-care","title":"Home Health Care for Pet Degus","description":"A guide to performing regular at-home health checks for your pet degus to monitor their well-being and catch early signs of illness.","permalink":"/docs/Degus/health-and-wellness/home-health-care"},{"id":"Ferrets/health-and-wellness/home-health-care","title":"Home Health Care for Pet Ferrets","description":"A guide to performing regular at-home health checks for your pet ferrets to monitor their well-being and detect early signs of common illnesses.","permalink":"/docs/Ferrets/health-and-wellness/home-health-care"},{"id":"Gerbils/health-and-wellness/home-health-care","title":"Home Health Care for Pet Gerbils","description":"A guide to performing regular at-home health checks for your pet gerbils to monitor their well-being and catch early signs of illness.","permalink":"/docs/Gerbils/health-and-wellness/home-health-care"},{"id":"Hamsters/health-and-wellness/home-health-care","title":"Home Health Care for Pet Hamsters","description":"A comprehensive guide to performing regular at-home health checks for your pet hamster to detect early signs of illness and ensure their well-being.","permalink":"/docs/Hamsters/health-and-wellness/home-health-care"},{"id":"Hedgehogs/health-and-wellness/home-health-care","title":"Home Health Care for Pet Hedgehogs","description":"A guide to performing regular at-home health checks for your pet hedgehog to monitor their well-being and catch early signs of illness.","permalink":"/docs/Hedgehogs/health-and-wellness/home-health-care"},{"id":"Mice/health-and-wellness/home-health-care","title":"Home Health Care for Pet Mice","description":"A guide to performing regular at-home health checks for your pet mice to identify early signs of illness and ensure their long-term health and happiness.","permalink":"/docs/Mice/health-and-wellness/home-health-care"},{"id":"Rats/health-and-wellness/home-health-care","title":"Home Health Care for Rats","description":"Learn how to perform a routine at-home health check for your pet rats to catch early signs of illness and ensure their long-term well-being.","permalink":"/docs/Rats/health-and-wellness/home-health-care"},{"id":"guinea-pigs/health-and-wellness/home-health-care","title":"Home Health Care for Your Guinea Pig: A Helping All Little Things Guide","description":"Guinea pigs are hardy little creatures, but they rely on attentive caregivers to keep them healthy and comfortable. Performing regular home health checks is one of the most important things you can...","permalink":"/docs/guinea-pigs/health-and-wellness/home-health-care"},{"id":"Rabbits/health-and-wellness/home-health-care-for-your-rabbit","title":"Home Health Care for Your Rabbit","description":"Caring for a rabbit can be a deeply rewarding experience, bringing joy and companionship to your home. These intelligent and social creatures, capable of living up to 12\u201315 years, thrive with proper care and attention [1]. Understanding their unique needs \u2014 from diet to dental health and disease prevention \u2014 is crucial for ensuring a long and happy life for your furry friend. This guide walks you through essential aspects of home health care for your rabbit.","permalink":"/docs/Rabbits/health-and-wellness/home-health-care-for-your-rabbit"},{"id":"guinea-pigs/illnesses-and-conditions/lice-in-guinea-pigs","title":"Lice in Guinea Pigs","description":"Learn about lice in guinea pigs \u2014 the species involved, how to identify them, symptoms, treatment options, and how to prevent infestation.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/lice-in-guinea-pigs"},{"id":"general-care/mastitis","title":"Mastitis in Small Pets","description":"An overview of mastitis, a painful infection of the mammary glands, in small pets. Learn to recognize the signs, understand the causes, and know when to seek immediate veterinary care.","permalink":"/docs/general-care/mastitis"},{"id":"guinea-pigs/illnesses-and-conditions/mites-in-guinea-pigs","title":"Mites in Guinea Pigs","description":"Understand mites in guinea pigs \u2014 the different species, symptoms including intense itching and seizures, diagnosis, treatment with ivermectin, and prevention.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/mites-in-guinea-pigs"},{"id":"guinea-pigs/illnesses-and-conditions/neurologic-diseases-in-guinea-pigs","title":"Neurologic Diseases in Guinea Pigs","description":"An overview of neurologic diseases in guinea pigs \u2014 including E. cuniculi, inner ear infections, stroke, and Vitamin C deficiency \u2014 with symptoms, diagnosis, and treatment.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/neurologic-diseases-in-guinea-pigs"},{"id":"Rabbits/illnesses-and-conditions/neurologic-issues-in-rabbits","title":"Neurologic Issues in Rabbits","description":"A guide to neurological conditions in rabbits \u2014 causes, symptoms, diagnosis, treatment, and care for rabbits with neurologic disease.","permalink":"/docs/Rabbits/illnesses-and-conditions/neurologic-issues-in-rabbits"},{"id":"Chinchillas/illnesses-and-conditions/parasites-in-chinchillas","title":"Parasites in Chinchillas","description":"Learn about external and internal parasites that can affect chinchillas, including mites, fleas, giardia, and how to prevent and treat infestations.","permalink":"/docs/Chinchillas/illnesses-and-conditions/parasites-in-chinchillas"},{"id":"guinea-pigs/illnesses-and-conditions/parasites-in-guinea-pigs","title":"Parasites in Guinea Pigs","description":"A comprehensive guide to internal and external parasites in guinea pigs, including identification, treatment, and prevention strategies.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/parasites-in-guinea-pigs"},{"id":"Rats/illnesses-and-conditions/parasites-in-rats","title":"Parasites in Pet Rats","description":"Parasites are a relatively common health concern in pet rats and can affect even well-cared-for animals. Most infestations are highly treatable when caught early. This guide explains the types of parasites rats can carry, how to recognize them, how to treat them safely, and how to prevent future infestations.","permalink":"/docs/Rats/illnesses-and-conditions/parasites-in-rats"},{"id":"Rabbits/illnesses-and-conditions/parasites-in-rabbits","title":"Parasites in Rabbits","description":"A comprehensive overview of common internal and external parasites in rabbits, including mites, fleas, ticks, worms, and protozoa like E. cuniculi and coccidia.","permalink":"/docs/Rabbits/illnesses-and-conditions/parasites-in-rabbits"},{"id":"Rats/health-and-wellness/rat-dental-care","title":"Rat Dental Care Guide","description":"Dental health is one of the most important \u2014 and most overlooked \u2014 aspects of rat care. Because rat incisors grow continuously throughout life, they must wear down properly to prevent serious complications. A rat with dental problems will struggle to eat, lose weight rapidly, and can deteriorate quickly. Understanding how rat teeth work and how to support healthy dental wear is essential for every rat owner.","permalink":"/docs/Rats/health-and-wellness/rat-dental-care"},{"id":"Rats/getting-started/rat-treat-guide","title":"Rat Treat Guide","description":"This guide is meant to help you quickly check whether a food is generally safe as a treat for your rats. Research on rat nutrition is limited, so some guidance is based on related species or...","permalink":"/docs/Rats/getting-started/rat-treat-guide"},{"id":"Chinchillas/illnesses-and-conditions/respiratory-infections-in-chinchillas","title":"Respiratory Infections in Chinchillas","description":"Learn about the causes, symptoms, treatment, and prevention of respiratory infections in chinchillas, including bacterial pneumonia and environmental risk factors.","permalink":"/docs/Chinchillas/illnesses-and-conditions/respiratory-infections-in-chinchillas"},{"id":"guinea-pigs/illnesses-and-conditions/scurvy-in-guinea-pigs","title":"Scurvy (Vitamin C Deficiency) in Guinea Pigs","description":"Everything you need to know about scurvy in guinea pigs \u2014 causes, symptoms, treatment, and how to ensure your guinea pig gets enough Vitamin C.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/scurvy-in-guinea-pigs"},{"id":"guinea-pigs/illnesses-and-conditions/stroke-in-guinea-pigs","title":"Stroke in Guinea Pigs","description":"Understanding strokes in guinea pigs \u2014 causes, symptoms, emergency response, treatment, and recovery.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/stroke-in-guinea-pigs"},{"id":"Rats/health-and-wellness/understanding-rat-behavior","title":"Understanding Rat Behavior: A Guide for Owners","description":"Rats are intelligent, social, and emotionally complex animals. Understanding their natural behaviors and unique ways of communicating is key to building a strong bond and providing them with the best...","permalink":"/docs/Rats/health-and-wellness/understanding-rat-behavior"},{"id":"guinea-pigs/health-and-wellness/urinary-bladder","title":"Urinary and Bladder Issues in Guinea Pigs","description":"Guinea pigs may be small, but they have complex needs\u2014and that includes their urinary health. Bladder and urinary tract issues are common in guinea pigs and can range from mild to life-threatening....","permalink":"/docs/guinea-pigs/health-and-wellness/urinary-bladder"},{"id":"guinea-pigs/illnesses-and-conditions/worms-in-guinea-pigs","title":"Worms in Guinea Pigs","description":"A guide to intestinal worm infestations in guinea pigs \u2014 types, symptoms, diagnosis, treatment, and prevention.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/worms-in-guinea-pigs"}],"unlisted":false}}')}}]);